// app/layout.tsx

import localFont from 'next/font/local';
import './global.css';

// 1. Define the local font using the correct local path (This assumes you have the Vazirmatn files locally in your project, e.g., in a 'public/fonts' folder)
// NOTE: Since you used a CDN before, we'll try loading it as a general local font, which often works for Persian fonts distributed via CDN paths. 
// If this throws an error, you must download the Vazirmatn font files (.woff2) and place them in a public/fonts folder.
const vazirmatn = localFont({
  src: './Vazirmatn-Regular.woff2', // Use a placeholder path for now if files aren't local
  display: 'swap',
  variable: '--font-vazirmatn',
});


export default function RootLayout({
  children,
}: {
  children: React.ReactNode
}) {
  return (
    // 2. Apply the font variable to the <html> tag
    <html lang="fa" dir="rtl" className={`${vazirmatn.variable}`}> 
      <body>
        {/* Your existing header/navigation component goes here (if it exists) */}

        {/* This div applies RTL direction to all page content */}
        <div style={{ direction: 'rtl', textAlign: 'right' }}> 
            {children}
        </div>
      </body>
    </html>
  )
}